use serde::{Deserialize, Serialize}; // We will use serde for easy serialization and deserialization of neuron states, which is useful for saving/loading models and for debugging purposes.

#[derive(Clone, Serialize, Deserialize, Debug)] // Deriving Clone, Serialize, Deserialize, and Debug traits for easy copying, serialization, and debugging of neuron instances.
pub struct LapicqueNeuron { // State variables and parameters for the LIF neuron model
    pub membrane_potential: f32, // Current charge state
    pub decay_rate: f32,         // How fast it "forgets" (Leak)
    pub threshold: f32,          // Limit to trigger an action potential
    pub base_threshold: f32,     // Resting threshold for dynamic modulation
    pub last_spike: bool,        // Tracks if it fired in the last step
    pub weights: Vec<f32>,      // Synaptic weights for each input channel
    pub last_spike_time: i64,   // Timestep of the most recent spike
}

impl Default for LapicqueNeuron { // Default values for the LIF neuron parameters and state
    fn default() -> Self { // Default values for the LIF neuron parameters and state
        Self { // Default values for the LIF neuron parameters and state
            membrane_potential: 0.0, // Start at resting potential
            decay_rate: 0.15, // Decay rate for the leak (15% per step)
            threshold: 0.02,  // Aggressively lowered threshold for more responsive firing
            base_threshold: 0.02, // Store the base threshold for dynamic modulation by inhibitory interneurons
            last_spike: false, // Initially, the neuron has not fired
            weights: Vec::new(), // Weights will be initialized later based on the number of input channels
            last_spike_time: -1, // No spikes have occurred yet, so we set this to -1 to indicate that
        }
    }
}

impl LapicqueNeuron { // Constructor for creating a new LIF neuron instance with default parameters
    pub fn new() -> Self { // Constructor for creating a new LIF neuron instance with default parameters
        Self::default() // Constructor for creating a new LIF neuron instance with default parameters
    }

    /// The Core Logic Step:
    /// 1. Add Input (Integration)
    /// 2. Lose Charge (Leak)
    pub fn integrate(&mut self, stimulus: f32) { // Integrate incoming stimulus and apply leak to the membrane potential
        // CHARGE: Add input stimulus to current state
        self.membrane_potential += stimulus;
        // LEAK: Decay towards resting potential (0.0) at the specified decay rate
        self.membrane_potential *= 1.0 - self.decay_rate;
    }

    /// Check if the neuron fires a spike based on the current membrane potential and threshold.
    /// If it fires, reset the membrane potential and update the last spike time.
    pub fn check_for_spike(&mut self, current_time: i64) -> bool { // Returns true if the neuron fired a spike, false otherwise
        let mut spikes = false; // Check if the membrane potential has reached or exceeded the threshold
        if self.membrane_potential >= self.threshold { // FIRE: Reset membrane potential and record spike time
            // FIRE: Reset membrane potential and record spike time
            self.membrane_potential = 0.0; // Reset to resting potential after firing
            self.last_spike = true; // Mark that the neuron fired in this step
            self.last_spike_time = current_time; // Update last spike time for STDP calculations
            spikes = true; // Indicate that a spike occurred
        } else { // No spike this step
            self.last_spike = false; // No spike this step
        }
        spikes // Return whether a spike occurred
    }
}